//! amplituhedron-taylor-bench — benchmark the Taylor-anchored Amplituhedron cache.
//!
//! GOAL
//! ----
//! Validate that the transition to the Taylor-anchored space (StabilityWeight)
//! correctly protects high-value volumes in the Amplituhedron cache.
//!
//! USAGE
//! -----
//!   cargo run --release --bin amplituhedron-taylor-bench

use distributed_inference::amplituhedron::AmplituhedronCache;
use std::time::Instant;

fn r(n: usize, fill: f32) -> Vec<f32> {
    vec![fill; n]
}

fn main() {
    println!("============================================================");
    println!(" Amplituhedron Taylor-Anchored Stability Benchmark");
    println!("============================================================");

    let mut cache = AmplituhedronCache::new();
    // Use a small capacity to force evictions.
    // 11 is the new Taylor default, but we'll use 4 for this bench to see
    // the "breathing" more clearly.
    cache.set_max_volumes(4);

    println!("[1] Seeding Taylor manifold (N=4, Taylor 11 default is 11)");

    // Seed 4 volumes.
    for i in 1..=4 {
        cache.capture(i as u64, 256, 0, 1, r(8, i as f32), r(64, i as f32));
    }
    let (h, m, e) = cache.stats();
    println!(
        " -> Initial state: hits={}, misses={}, evictions={}",
        h, m, e
    );

    println!(
        "
[2] Elevating 'Standing Wave Aeon' volume (Key 1) via hits"
    );
    // Simulate high traffic to Key 1 (the anchor).
    for _ in 0..100 {
        let _ = cache.replay(1, 256, 0, 1);
    }
    let (h, m, e) = cache.stats();
    println!(
        " -> After 100 hits on Key 1: hits={}, misses={}, evictions={}",
        h, m, e
    );

    println!(
        "
[3] Triggering capacity pressure (Inserting Keys 5-10)"
    );
    // Insert new keys to force eviction.
    // In the old LRU/Density model, Key 1 might eventually be evicted if
    // others are replayed more or have longer prefixes.
    // In the Taylor Stability model: stability = R - min(hit_count, R) + 1.
    // Key 1 (hit_count=100) has deficit = 199 - 100 + 1 = 100.
    // Keys 2-4 (hit_count=0) have deficit = 199 - 0 + 1 = 200.
    // HIGHEST deficit is evicted first. So Keys 2, 3, 4 should go first.

    let t0 = Instant::now();
    for i in 5..=10 {
        cache.capture(i as u64, 256, 0, 1, r(8, i as f32), r(64, i as f32));
    }
    let elapsed = t0.elapsed();

    let (h, m, e) = cache.stats();
    println!(
        " -> Pressure applied: hits={}, misses={}, evictions={} ({} ms)",
        h,
        m,
        e,
        elapsed.as_millis()
    );

    println!(
        "
[4] Verifying Standing Wave Anchor Protection"
    );
    let hit_1 = cache.replay(1, 256, 0, 1);
    if hit_1.is_some() {
        println!(" ✅ Key 1 (Anchor) PRESERVED after 6 evictions.");
    } else {
        println!(" ❌ Key 1 (Anchor) EVICTED. Taylor stability failed.");
    }

    // Check which other keys survived.
    let mut survivors = Vec::new();
    for i in 1..=10 {
        if cache.replay(i as u64, 256, 0, 1).is_some() {
            survivors.push(i);
        }
    }
    println!(" -> Survivors: {:?}", survivors);
    println!(" -> Heat Released: {}", cache.heat_released());

    println!(
        "
[5] Performance verification"
    );
    // Ensure that the stability formula doesn't add significant latency.
    let mut perf_cache = AmplituhedronCache::new();
    perf_cache.set_max_volumes(11);
    let t_perf = Instant::now();
    for i in 0..1000 {
        perf_cache.capture(i as u64, 256, 0, 1, r(1, 0.0), r(1, 0.0));
        let _ = perf_cache.replay(i as u64, 256, 0, 1);
    }
    let elapsed_perf = t_perf.elapsed();
    println!(
        " -> 1000 captures/replays: {:?} total ({:?} per op)",
        elapsed_perf,
        elapsed_perf / 2000
    );

    println!(
        "
============================================================"
    );
    println!(" Benchmark Complete.");
    println!("============================================================");
}
